diff --git a/.claude/agent-memory/code-reviewer/MEMORY.md b/.claude/agent-memory/code-reviewer/MEMORY.md
index d77257b5c..83027bbb6 100644
--- a/.claude/agent-memory/code-reviewer/MEMORY.md
+++ b/.claude/agent-memory/code-reviewer/MEMORY.md
@@ -297,6 +297,42 @@
   in `toolColors.ts`. Missing entries don't cause crashes but leave other components that derive color
   by tool name with `undefined` (falls through to no class).
 - When adding a new renderer, add its color entry to `TOOL_COLORS` in the same commit.
+## Radix DropdownMenuTrigger + asChild + onClick Conflict Pattern
+
+- When `<DropdownMenuTrigger asChild>` wraps a child with its own `onClick`, Radix's Slot merges
+  BOTH handlers. If the child's `onClick` calls `setOpen(false)` (to suppress the dropdown for a
+  quick-open action), the dropdown STILL opens first (Radix toggle runs), then closes — visible flicker.
+- Fix: either don't use `DropdownMenuTrigger` on the quick-open button (use a sibling trigger for
+  the chevron only), or put the `DropdownMenuTrigger` on the chevron/separator button only.
+
+## Last-Used App Persistence Pattern
+
+- `useLastOpenInApp` / `getLastOpenInAppId` / `setLastOpenInAppId` live in
+  `apps/web/src/shared/hooks/useLastOpenInApp.ts` and are exported from `shared/hooks/index.ts`.
+- Pattern: `setLastAppId(appId)` must be called at EVERY `openIn(appId, path)` call site.
+  `WorkspaceHeader.tsx`'s `HeaderOpenButton` currently skips this call — Cmd+O will not reflect
+  choices made from that dropdown.
+
+## Spurious useEffect Deps Pattern
+
+- `useKeyboardShortcuts` includes `selectedWorkspace` and `modalStates` in its `useEffect` deps
+  array but neither is read inside the effect body. This causes the global keydown listener to
+  be torn down and re-registered on every workspace switch and modal state change.
+  Fix: remove those deps, or move logic that needs them into the callback params.
+
+## getInstalledAppsList() Race / Cache Pattern (native-handlers.ts)
+
+- `cachedInstalledApps` is a module-level variable with no in-flight guard. Two simultaneous IPC
+  calls before the first resolves will both execute the full mdfind loop in parallel and both write
+  to `/tmp/opendevs-icon-{id}.png` at the same time.
+- Fix: cache a Promise while in-flight: `let inflightPromise: Promise<InstalledApp[]> | null = null`.
+
+## mdfind bundleId Query Safety
+
+- `mdfind` in `native-handlers.ts` interpolates `app.bundleId` directly into the query string:
+  `kMDItemCFBundleIdentifier == '${app.bundleId}'`. Values come from SUPPORTED_APPS which is
+  hardcoded, so this is safe. No user-controlled data reaches mdfind.
+
 ## See Also

 - `patterns-deep.md` — overflow notes: error classification, chat virtualization, PRStatus, border radius, sidecar resume
diff --git a/apps/desktop/main/native-handlers.ts b/apps/desktop/main/native-handlers.ts
index e2fbab22f..cf19f21ca 100644
--- a/apps/desktop/main/native-handlers.ts
+++ b/apps/desktop/main/native-handlers.ts
@@ -396,39 +396,48 @@ interface InstalledApp {
 }

 let cachedInstalledApps: InstalledApp[] | null = null;
+let inflightPromise: Promise<InstalledApp[]> | null = null;

 async function getInstalledAppsList(): Promise<InstalledApp[]> {
   if (cachedInstalledApps) return cachedInstalledApps;
+  if (inflightPromise) return inflightPromise;
   if (process.platform !== "darwin") return [];
+  inflightPromise = loadInstalledApps();
+  return inflightPromise;
+}

+async function loadInstalledApps(): Promise<InstalledApp[]> {
+  const fs = await import("fs/promises");
   const installed: InstalledApp[] = [];

-  for (const app of SUPPORTED_APPS) {
+  for (const appDef of SUPPORTED_APPS) {
     try {
-      // Find the app by bundle ID
       const { stdout } = await execFileAsync("mdfind", [
-        `kMDItemCFBundleIdentifier == '${app.bundleId}'`,
+        `kMDItemCFBundleIdentifier == '${appDef.bundleId}'`,
       ]);
       const appPath = stdout.trim().split("\n")[0];
       if (!appPath || !appPath.endsWith(".app")) continue;

-      // Extract icon as base64 PNG using sips
+      // Extract icon: read CFBundleIconFile from Info.plist, convert with sips
       let icon: string | undefined;
       try {
-        const iconPath = `${appPath}/Contents/Resources/AppIcon.icns`;
-        const tmpPng = `/tmp/opendevs-icon-${app.id}.png`;
-        await execFileAsync("sips", [
-          "-s",
-          "format",
-          "png",
-          "-z",
-          "64",
-          "64",
-          iconPath,
-          "--out",
-          tmpPng,
-        ]);
-        const fs = await import("fs/promises");
+        // Resolve actual icon filename from plist (apps use different names)
+        let iconFileName = "AppIcon.icns";
+        try {
+          const { stdout: plistOut } = await execFileAsync("/usr/libexec/PlistBuddy", [
+            "-c",
+            "Print :CFBundleIconFile",
+            `${appPath}/Contents/Info.plist`,
+          ]);
+          const name = plistOut.trim();
+          if (name) iconFileName = name.endsWith(".icns") ? name : `${name}.icns`;
+        } catch {
+          // Fall back to AppIcon.icns
+        }
+
+        const icnsPath = `${appPath}/Contents/Resources/${iconFileName}`;
+        const tmpPng = `/tmp/opendevs-icon-${appDef.id}.png`;
+        await execFileAsync("sips", ["-s", "format", "png", "-z", "64", "64", icnsPath, "--out", tmpPng]);
         const buf = await fs.readFile(tmpPng);
         icon = `data:image/png;base64,${buf.toString("base64")}`;
         await fs.unlink(tmpPng).catch(() => {});
@@ -436,12 +445,13 @@ async function getInstalledAppsList(): Promise<InstalledApp[]> {
         // Icon extraction failed — will use fallback letter
       }

-      installed.push({ id: app.id, name: app.name, path: appPath, icon });
+      installed.push({ id: appDef.id, name: appDef.name, path: appPath, icon });
     } catch {
       // App not installed — skip
     }
   }

   cachedInstalledApps = installed;
+  inflightPromise = null;
   return installed;
 }
